var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 오늘부터 판도라에서 일하게 된 서가람입니다.","JPN":"はじめまして。本日からパンドラで働くことになりました、カワセ・ヒカリです。","ENG":"Hello. I'm Seo Garam, and I will be working at Pandora starting today.","TWN":"初次見面，我是從今天開始在潘朵拉工作的徐嘉蘭。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"시뮬레이션 개발 부서에 들어오기 위해, 지금까지 많은 경력을 쌓으며 노력해 왔어요.","JPN":"シミュレーション開発部署に入るために、今まで色んな経験を積んで努力してきました。","ENG":"I worked hard to build my career so that I could join the Simulation Department in Pandora.","TWN":"為了進入模擬開發部門，我一直在積累經驗並努力工作。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"모두 잘 부탁드릴게요! 열심히 하겠습니다!","JPN":"よろしくお願いします！　一生懸命頑張ります！","ENG":"I look forward to working with you all! I'll do my best!","TWN":"大家請多指教！我會努力的！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"환영해요……. 가람 씨.","JPN":"歓迎します……ヒカリさん。","ENG":"Welcome... Garam.","TWN":"歡迎……嘉蘭。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"진보라라고 해요……. 잘 부탁해요.","JPN":"タカダ・シホです……よろしく。","ENG":"I'm Jin Bora... I look forward to working with you too.","TWN":"我叫陳寶拉……請多關照。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"와~ 같이 일하게 돼서 영광이에요!","JPN":"わ～一緒にお仕事できて光栄です！","ENG":"Wow! It's an honor to work with you!","TWN":"哇～能和你一起工作真是太榮幸了！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"보라 씨의 명성은 예전부터 많이 들어왔답니다.","JPN":"シホさんの名声は昔から聞いています。","ENG":"I've heard a lot about you, Ms. Jin!","TWN":"久仰大名。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 시리즈와 시뮬레이션 개발의 권위자시잖아요?","JPN":"カウンターズシリーズとシミュレーション開発の権威者じゃないですか。","ENG":"You're an expert in the field of simulation, not to mention you were in charge of developing the Counters series!","TWN":"你可是制裁者系列和模擬開發的權威啊？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"부끄러워요…… 그렇게 띄워주면.","JPN":"恥ずかしいです……そんなにおだてられると。","ENG":"Please don't... praise me like that.","TWN":"好害羞……被你這麼誇獎。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"엇, 왜 그러세요……?","JPN":"え、どうしました……？","ENG":"Huh? Why are you looking at me like that...?","TWN":"啊，怎麼了……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"오피스레이디Y 맞죠……? 그 란도셀.","JPN":"オフィスレディーYですよね……？　そのランドセル。","ENG":"That's Office Lady Y, right...? The randoseru?","TWN":"是上班女郎Y吧……？那個書包。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"전체적으로 쏙 닮았네요. 란도셀뿐만 아니라.","JPN":"全体的にそっくりですね。ランドセルだけじゃなくて。","ENG":"You look just like her. Not just the randoseru.","TWN":"整體上非常相似。不僅僅是書包。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하, 역시 알아보셨군요? 전 스트리트 카운터의 왕팬이거든요.","JPN":"あはは、やっぱりわかってくれましたか！　私、ストリート・カウンターの大ファンなんです。","ENG":"Ah hah hah, did you notice? I'm a huge fan of Street Counter.","TWN":"哈哈哈，果然認出來了吧？我是街頭制裁者的粉絲喔。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"보라 씨라면 고증을 지키고픈 팬의 마음, 잘 아시죠?","JPN":"シホさんは原作を再現したいファンの気持ち、わかりますよね？","ENG":"I'm sure you know how important the details are to a fan, right?","TWN":"寶拉應該很了解的粉絲心情吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"<color=#ffd34c>……닮았네요. 제가 알던 아이와.</color>","JPN":"<color=#ffd34c>……似てますね。私の知ってる子と。</color>","ENG":"<color=#ffd34c>...You resemble someone I know.</color>","TWN":"<color=#ffd34c>……真像。和我認識的孩子。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"응? 그게 누구죠?","JPN":"え？　誰ですか？","ENG":"Hmm? Who might that be?","TWN":"嗯？那是誰？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"안내할게요…… 자리로.","JPN":"案内します……席に。","ENG":"I'll show you... to your seat.","TWN":"我來帶路……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"개발 중인…… 저희 프로젝트도.","JPN":"開発中の……私たちのプロジェクトも。","ENG":"And the project... we are working on.","TWN":"我們開發中的……專案。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네! 벌써부터 일할 생각에 정말 두근거리네요!","JPN":"はい！　ここで仕事ができるんだと思うとわくわくしてきます！","ENG":"Okay! I'm so excited to start work!","TWN":"是的！一想到要工作就讓我心跳加速！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L34_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"혹시 프로젝트명이 뭔지 알 수 있을까요?","JPN":"プロジェクト名をお伺いしてもいいでしょうか？","ENG":"Can you tell me the project name?","TWN":"請問可以知道項目名稱嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"카운터즈…… 레거시.","JPN":"カウンターズ……レガシー。","ENG":"Counters... Legacy.","TWN":"制裁者……的遺產。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"다들 모이셨나요? 그럼 회의 시작하도록 하겠습니다!","JPN":"皆さん集まりましたか？　では会議を始めます！","ENG":"Is everyone here? Then, I'll start the meeting!","TWN":"大家都到齊了嗎？那我們開始會議吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시에는 침식체뿐만 아니라, 카운터끼리의 대인전도 디자인해 보려 합니다.","JPN":"カウンターズ・レガシーに侵食体だけじゃなく、カウンター同士の対人戦も実装しようと思います。","ENG":"For Counters Legacy, I am planning to add PvP mode where Counters can battle each other and not only the C.O.s.","TWN":"制裁者的遺產不僅會設計對抗侵蝕體的戰鬥，還會設計制裁者之間的對戰。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시는 카운터의 모의전투 시뮬레이션을 기반으로 개발되었죠.","JPN":"カウンターズ・レガシーは、カウンターの模擬戦闘シミュレーションを基に開発されたものです。","ENG":"Counters Legacy was developed based on Counter simulation training.","TWN":"制裁者的遺產是基於制裁者的模擬戰鬥開發的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그렇기에 다양한 전투 경험을 쌓을 수 있게 하는 것이 중요하다고 생각해요.","JPN":"だからこそ、様々な戦闘経験を積める環境を提供することが大事だと思います。","ENG":"That's why I think it's important for them to gain a variety of combat experiences.","TWN":"因此，我認為讓他們積累各種戰鬥經驗是很重要的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이를테면 리플레이서 사태 같은 경우를 생각해 볼 수 있죠.","JPN":"たとえば、リプレイサー事件のような場合。","ENG":"For instance, we can think of something like the Replacer incident.","TWN":"比如說克隆集團事件之類的情況。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L44_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그들의 기술력은 이미 전 세계에 유포되어 다양한 범죄를 저지르고 있어요.","JPN":"彼らの技術力はすでに全世界に広まって、様々な犯罪に繋がっています。","ENG":"Their technology has spread all throughout the world and is causing various crimes.","TWN":"他們的技術已經傳播到全世界，正在進行各種犯罪活動。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"앞으로 미래에 그런 집단이 또 나타나지 않을 거라는 보장도 없죠.","JPN":"将来、同じような集団がまた現れる可能性だってあります。","ENG":"There is no guarantee that there won't be another group like them in the future.","TWN":"將來沒有保證不會再出現那樣的團體。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L46_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저희 판도라 사는 관리국과 협업한 경험이 많으니까, 분명 리플레이서의 데이터를 제공받을 수 있을 거라 생각해요.","JPN":"私たちパンドラ社は管理局と協力してきた経験が多いので、きっとリプレイサーのデータも提供してもらえると思います。","ENG":"Since Pandora has a lot of experience working with the Administration, I'm certain that they can provide us with some data on the Replacers.","TWN":"我們潘朵拉公司有很多與管理局合作的經驗，我認為一定可以獲得克隆的相關資料。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"다녀왔어요…… 출장. 관리국에.","JPN":"行ってきました……出張。管理局に。","ENG":"I'm back... from the business trip. To the Administration.","TWN":"我從管理局出差……回來了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"앗, 선배! 다녀오셨어요?","JPN":"あっ、先輩！　おかえりなさい！","ENG":"Oh, Bora! You're back!","TWN":"前輩！你回來了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"리플레이서의 데이터…… 협상해 봤어요.","JPN":"リプレイサーのデータ……交渉してみました。","ENG":"I tried to negotiate... about the Replacer data.","TWN":"克隆集團的資料……試著協商過了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저, 정말요?! 그쪽에서 뭐라던 가요?","JPN":"ほ、本当ですか！？　返事はどうでした？","ENG":"R-really?! What did they say?","TWN":"真，真的嗎？！那邊說了什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……유감.","JPN":"……残念。","ENG":"...Sorry.","TWN":"……真遺憾。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"제공해 줄 수 없다 했어요…… 아직은.","JPN":"提供できないそうです……今は。","ENG":"They said they couldn't provide it... yet.","TWN":"我說過現在還不能提供……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"하…… 오랫동안 준비한 기획이었는데.","JPN":"はあ……時間をかけて準備した企画だったのに。","ENG":"*Sigh* I've been preparing this for such a long time.","TWN":"哀……這是我準備了很久的計畫。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"상심하지 마세요…… 너무.","JPN":"あまり……落ち込まないで。","ENG":"Don't be so... discouraged.","TWN":"不要太傷心……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"힘써 볼 테니까…… 최대한.","JPN":"頑張ってみます……できる限り。","ENG":"I'll see what... I can do.","TWN":"我會盡力的……盡可能做到最好。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"고마워요 선배. 조금 위로가 되네요.","JPN":"ありがとうございます、先輩。少し慰めになりました。","ENG":"Thanks, Bora. That's reassuring.","TWN":"謝謝你，前輩。感覺有好一點。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"해야 할 일을 할 뿐……","JPN":"やるべきことをしただけ……","ENG":"I'm just doing what I must...","TWN":"我只是做我該做的事……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……있잖아요. 제가 여기 입사한 이유. 선배를 동경했기 때문이에요.","JPN":"……あの、私がここに入社した理由は、先輩に憧れていたからです。","ENG":"...You know, I applied to this company because... I look up to you.","TWN":"……那個，我之所以會來這裡工作，是因為我很仰慕前輩。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"오피스레이디Y, 선배가 전부 디자인하셨죠?","JPN":"オフィスレディーY、全部先輩のデザインですよね？","ENG":"Office Lady Y. You designed her, didn't you?","TWN":"上班女郎Y，都是前輩設計的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"전 어른이 돼서도 방구석 폐인으로 살았거든요.","JPN":"私、大人になってもひきこもりのままだったんです。","ENG":"I had been cooped up in my room even after becoming an adult.","TWN":"我長大後也一直是個宅女。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"우연히 스트리트 카운터8를 플레이 하다가 이 캐릭터를 알게 되었어요.","JPN":"偶然ストリート・カウンター8をプレイして、このキャラクターを知りました。","ENG":"But I happened to find out about her while playing Street Counter 8.","TWN":"偶然玩街頭制裁者8時，認識了這個角色。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"어른이 돼서도 방황만 하다, 어린 시절의 동경심 하나로 일어선 캐릭터.","JPN":"大人になっても迷い続け、幼い頃の憧れだけで立ち直ったキャラクター。","ENG":"She's a character who lost her way even into adulthood but got back up because of childhood admiration.","TWN":"長大後依然彷徨不定，靠著兒時的憧憬站起來的角色。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……마치 절 투영한 것만 같았어요. 동경하게 되었죠.","JPN":"……まるで自分を見てるような気分でした。憧れたんです。","ENG":"...She felt like a projection of me. So, I came to admire her.","TWN":"……彷彿看到了曾經的自己。我開始憧憬起來了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이 캐릭터를 디자인한 선배는 저에게 있어 영웅이나 다름없어요.","JPN":"このキャラクターをデザインした先輩は、私にとって英雄です。","ENG":"And since you were the one who designed this character, you're like a hero to me.","TWN":"設計這個角色的前輩對我來說就像英雄一樣。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그래서…… 저도 개발자가 되어 언젠가 선배와 함께 일하고 싶은 마음마저 들게 되었죠.","JPN":"だから……私も開発者になって、いつか先輩と一緒に働きたいと思い始めました。","ENG":"That's why... I decided to become a developer to one day work with you.","TWN":"所以……我也想成為開發者，某天能和前輩一起工作。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하, 동기가 좀 이상하죠?","JPN":"あはは、変な動機ですよね？","ENG":"Ah hah hah. I know it's a weird motivation.","TWN":"哈哈哈，動機有點奇怪吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"전혀…… 동경하는 마음은…… 중요해요.","JPN":"そんなことない……憧れる気持ちは……大切です。","ENG":"Not at all... admiration... is important.","TWN":"完全沒有……憧憬的心情……很重要。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"응원하고 있어요…… 진심으로.","JPN":"応援しています……心から。","ENG":"I am rooting for you... with all my heart.","TWN":"我在為你加油……真的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"뭐든 도와줄게요. 할 수 있는 일이 있다면……","JPN":"どんなことでも力を貸します。できることがあれば……","ENG":"I'll help. With whatever I can...","TWN":"我會幫忙的。如果有我能做的事……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"하핫, 두고 보세요. 언젠간 선배를 뛰어넘고 판도라 사의 기둥이 될 테니까요!","JPN":"ははっ、見ててくださいね。いつか先輩を越えて、パンドラ社の大黒柱になってみせますから！","ENG":"Haha, just you wait. I'll become someone important at Pandora and even surpass you!","TWN":"哈哈，等著瞧吧，總有一天我會超越前輩，成為潘朵拉公司的支柱！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L31_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"저기, 보라 씨?","JPN":"あの、シホさん？","ENG":"Um, Bora?","TWN":"呃，寶拉？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"응……? 왜요?","JPN":"うん……？　どうしましたか？","ENG":"Yes...? What is it?","TWN":"嗯……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"아까부터 무서운 얼굴 하고 계신데, 괜찮으세요?","JPN":"さっきから怖い顔をしてますけど、大丈夫ですか？","ENG":"Your expression looks awfully grim. Are you okay?","TWN":"從剛才開始你就一直擺著一張嚇人的臉，沒事吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아…… 미안해요.","JPN":"あ……すみません。","ENG":"Oh... I'm sorry.","TWN":"啊……對不起。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"어때요……? 유저들의 동향.","JPN":"どうですか……？　ユーザーの反応。","ENG":"How does it look...? The user trends.","TWN":"怎麼樣……？玩家們的反應。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"엄청나죠. 설마 이렇게까지 많은 유저들이 몰릴 줄은 몰랐어요.","JPN":"すごいですよ。まさかここまで多くのユーザーが集まるとは思いませんでした。","ENG":"It's outstanding. Who would've thought that so many people would join.","TWN":"很厲害吧，沒想到會有這麼多玩家湧入。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"상태는요……? 오버로드.","JPN":"状態は……？　オーバーロード。","ENG":"How is it…? Overlord.","TWN":"情況如何……？超載。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"안정적이에요. 가람 씨가 잘해주고 계시거든요.","JPN":"安定的です。ヒカリさんが頑張ってくれているので。","ENG":"It's stable. Garam is working hard at that.","TWN":"很穩定，因為嘉蘭做得很好。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"자신이 동경하는 모습을 비춰 준다니, 굉장하지 않아요?","JPN":"自分の憧れる姿を映す……すごいですね。","ENG":"A reflection of the image you admire the most. Isn't it amazing?","TWN":"能映照出自己憧憬的樣子，不是很棒嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"좋죠…… 동경하는 마음을…… 보여주는 건.","JPN":"いいですよね……憧れの気持ちを……見せてくれるのは。","ENG":"It's good... to show... one's admiration.","TWN":"展現出……憧憬之情……蠻好的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"하지만 누군가는…… 보고 있을 수도 있잖아요.","JPN":"でも誰かの目には……見えているかもしれません。","ENG":"But someone... might have…","TWN":"但是也有人……可能正在覬覦呢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"일그러진…… 동경.","JPN":"歪んだ……憧れが。","ENG":"A twisted version of... the admiration.","TWN":"扭曲的……憧憬。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"이, 이것이 카운터의 힘인가? 시뮬레이션이라지만 정말 최고잖아.","JPN":"こ、これがカウンターの力？　シミュレーションだけどすごいじゃん。","ENG":"I-is this the power of a Counter? I know it's only a simulation, but this is awesome!","TWN":"這，這就是制裁者的力量嗎？雖然是模擬，但真的很厲害啊。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"하하, 카운터 자식들. 지금까지 자기들만 이런 힘을 누려 왔다니……!","JPN":"はは、カウンターのやつらめ。今まで自分たちだけこんな力を振るってたのが……！","ENG":"Haha! Those Counter snobs. They've kept this kind of power to themselves all along...?!","TWN":"哈哈，這些制裁者傢伙。到現在為止，只有他們享受過這種力量……！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"그렇다면 이곳이라면 우리들이 동경했던 꿈을 이룰 수 있는 걸까?","JPN":"それじゃ、ここなら憧れていた夢を叶えられるのかな？","ENG":"Then, maybe this is the place we can finally achieve our dreams!","TWN":"那麼在這裡，我們能實現我們所憧憬的夢想嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"카운터가 되어 히어로가 되고 싶었던 꿈 맞지?","JPN":"カウンターになって、ヒーローになりたいという夢か？","ENG":"The dream of becoming a Counter and a hero, right?","TWN":"成為制裁者，成為英雄的夢想，對吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"맞아…… 가능할지도 몰라.","JPN":"そう……できるかもしれない。","ENG":"Yeah... I think that's possible now.","TWN":"沒錯……也許可以實現。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}}]`);export{e as default};